mapper.select:
SELECT id, operator_id AS operatorId, operator_name AS operatorName, operated_at AS operatedAt, operation_type AS operationType, module, target_type AS targetType, target_id AS targetId, target_label AS targetLabel, change_summary AS changeSummary, change_detail AS changeDetail, ip, user_agent AS userAgent FROM admin_operation_log
ORDER BY operated_at DESC
LIMIT #{limit}
OFFSET #{offset}
